        action: "connect",
        correlationId: context.correlationId,
        code: error?.code,
        error
      });
      throw error;
    }
  }
}

module.exports = connectDb;

const { randomUUID } = require("node:crypto");

const CORRELATION_HEADER = "x-correlation-id";
const REQUEST_ID_HEADER = "x-request-id";

function normalizeHeaderValue(value) {
  if (!value) return "";
  if (Array.isArray(value)) return String(value[0] || "").trim();
  return String(value).trim();
}

function correlationId(req, res, next) {
  const incomingCorrelationId = normalizeHeaderValue(req.headers[CORRELATION_HEADER]);
  const incomingRequestId = normalizeHeaderValue(req.headers[REQUEST_ID_HEADER]);
  const id = incomingCorrelationId || incomingRequestId || randomUUID();

  req.correlationId = id;
  res.setHeader("X-Correlation-Id", id);
  next();
}

module.exports = correlationId;

const logger = require("../utils/logger");

function requestLogger(req, res, next) {
  const start = process.hrtime.bigint();

  res.on("finish", () => {
    const end = process.hrtime.bigint();
    const durationMs = Number(end - start) / 1_000_000;

    logger.info("api-call", {
      method: req.method,
      path: req.originalUrl,
      status: res.statusCode,
      durationMs: Math.round(durationMs * 100) / 100
    });
  });

  next();
}

module.exports = requestLogger;

const logger = require("../utils/logger");

function requestLogger(req, res, next) {
  const start = process.hrtime.bigint();
  const correlationId = req.correlationId || "n/a";

  res.on("finish", () => {
    const end = process.hrtime.bigint();
    const durationMs = Number(end - start) / 1_000_000;

    logger.info("api-call", {
      correlationId,
      method: req.method,
      path: req.originalUrl,
      status: res.statusCode,
      durationMs: Math.round(durationMs * 100) / 100,
      ip: req.ip,
      userAgent: req.get("user-agent") || ""
    });
  });

  next();
}

module.exports = requestLogger;

function log(level, message, meta = {}) {
  const payload = {
    ts: new Date().toISOString(),
    level,
    message,
    ...meta
  };
  const line = JSON.stringify(payload);
  if (level === "error") {
    console.error(line);
    return;
  }
  console.log(line);
}

function info(message, meta) {
  log("info", message, meta);
}

function error(message, meta) {
  log("error", message, meta);
}

module.exports = {
  info,
  error
};

function log(level, message, meta = {}) {
  const error = meta.error;
  const safeMeta = { ...meta };
  delete safeMeta.error;

  const payload = {
    ts: new Date().toISOString(),
    level,
    service: "sprint-cc-backend",
    env: process.env.NODE_ENV || "development",
    pid: process.pid,
    message,
    ...safeMeta
  };

  if (error instanceof Error) {
    payload.error = {
      name: error.name,
      message: error.message,
      stack: error.stack
    };
  }

  const line = JSON.stringify(payload);
  if (level === "error") {
    console.error(line);
    return;
  }
  console.log(line);
}

function info(message, meta) {
  log("info", message, meta);
}

function error(message, meta) {
  log("error", message, meta);
}

module.exports = {
  info,
  error
};

const test = require("node:test");
const assert = require("node:assert/strict");
const request = require("supertest");
const mongoose = require("mongoose");
const { MongoMemoryServer } = require("mongodb-memory-server");

let mongo;
let app;

async function closeConnections() {
  await mongoose.connection.dropDatabase();
  await mongoose.connection.close();
  await mongo.stop();
}

test("backend upserts and reads submissions", async (t) => {
  mongo = await MongoMemoryServer.create();
  process.env.MONGO_URI = mongo.getUri();
  process.env.VERCEL = "1";

  app = require("../server");

  t.after(async () => {
    await closeConnections();
  });

  const payload = {
    Team: "McLaren",
    ProjectKey: "MC",
    SprintNo: "35.1",
    PI: "35",
    submittedDate: "2026-06-22",
    submittedBy: "Test User",
    TeamSize: 1,
    TotalDays: 8,
    SprintOverhead: 1.6,
    SprintCapacity: 6.4,
    DevCapacityDays: 6.4,
    TestCapacityDays: 0,
    DevPercent: 100,
    TestPercent: 0,
    Notes: "First submit",
    Roster: [
      { name: "Alice", role: "Full Stack Dev", ph: 0, al: 0, other: 0, pct: 100, notes: "", AvailableDays: 8 }
    ]
  };

  const first = await request(app).post("/api/submissions/upsert").send(payload);
  assert.equal(first.status, 200);
  assert.equal(first.body.success, true);
  assert.equal(first.body.isReplace, false);

  const read = await request(app).get("/api/submissions/MC/35.1");
  assert.equal(read.status, 200);
  assert.equal(read.body.found, true);
  assert.equal(read.body.record.Team, "McLaren");

  const second = await request(app)
    .post("/api/submissions/upsert")
    .send({ ...payload, Notes: "Second submit" });
  assert.equal(second.status, 200);
  assert.equal(second.body.isReplace, true);

  const list = await request(app).get("/api/submissions");
  assert.equal(list.status, 200);
  assert.equal(Array.isArray(list.body), true);
  assert.equal(list.body.length, 1);
  assert.equal(list.body[0].Notes, "Second submit");
});

const test = require("node:test");
const assert = require("node:assert/strict");
const request = require("supertest");
const mongoose = require("mongoose");
const { MongoMemoryServer } = require("mongodb-memory-server");

let mongo;
let app;

async function closeConnections() {
  await mongoose.connection.dropDatabase();
  await mongoose.connection.close();
  await mongo.stop();
}

test("backend upserts and reads submissions", async (t) => {
  mongo = await MongoMemoryServer.create();
  process.env.MONGO_URI = mongo.getUri();
  process.env.VERCEL = "1";

  app = require("../server");

  t.after(async () => {
    await closeConnections();
  });

  const payload = {
    Team: "McLaren",
    ProjectKey: "MC",
    SprintNo: "35.1",
    PI: "35",
    submittedDate: "2026-06-22",
    submittedBy: "Test User",
    TeamSize: 1,
    TotalDays: 8,
    SprintOverhead: 1.6,
    SprintCapacity: 6.4,
    DevCapacityDays: 6.4,
    TestCapacityDays: 0,
    DevPercent: 100,
    TestPercent: 0,
    Notes: "First submit",
    Roster: [
      { name: "Alice", role: "Full Stack Dev", ph: 0, al: 0, other: 0, pct: 100, notes: "", AvailableDays: 8 }
    ]
  };

  const first = await request(app).post("/api/submissions/upsert").send(payload);
  assert.equal(first.status, 200);
  assert.equal(first.body.success, true);
  assert.equal(first.body.isReplace, false);
  assert.ok(first.headers["x-correlation-id"]);

  const read = await request(app)
    .get("/api/submissions/MC/35.1")
    .set("x-correlation-id", "test-corr-id");
  assert.equal(read.status, 200);
  assert.equal(read.body.found, true);
  assert.equal(read.body.record.Team, "McLaren");
  assert.equal(read.headers["x-correlation-id"], "test-corr-id");

  const second = await request(app)
    .post("/api/submissions/upsert")
    .send({ ...payload, Notes: "Second submit" });
  assert.equal(second.status, 200);
  assert.equal(second.body.isReplace, true);

  const list = await request(app).get("/api/submissions");
  assert.equal(list.status, 200);
  assert.equal(Array.isArray(list.body), true);
  assert.equal(list.body.length, 1);
  assert.equal(list.body[0].Notes, "Second submit");
});

const Submission = require("../models/Submission");
const Sprint = require("../models/Sprint");
const { cleanRoster } = require("../utils/roster");

const DAY_MS = 24 * 60 * 60 * 1000;

function toDateKey(value) {
  return new Date(value).toISOString().slice(0, 10);
}

function addDays(value, days) {
  return new Date(new Date(value).getTime() + days * DAY_MS);
}

function normalizeObjectives(objectives, objective) {
  const values = Array.isArray(objectives)
    ? objectives
    : typeof objective === "string" && objective.trim()
      ? [objective]
      : [];

  return values
    .map((item) => String(item || "").trim())
    .filter(Boolean);
}

function normalizeNullableNumber(value) {
  if (value === "" || value === null || value === undefined) {
    return null;
  }

  const parsed = Number(value);
  if (!Number.isFinite(parsed)) {
    const err = new Error("Numeric submission fields must contain valid numbers");
    err.statusCode = 400;
    throw err;
  }

  return parsed;
}

function sameObjectives(left = [], right = []) {
  if (left.length !== right.length) return false;
  return left.every((value, index) => value === right[index]);
}

function sameNullableNumber(left, right) {
  return (left ?? null) === (right ?? null);
}

async function resolveSprintWindow(payload) {
  const sprintNo = String(payload.SprintNo || "").trim();
  if (!sprintNo) return null;

  const sprint = await Sprint.findOne({ sprint: sprintNo }).lean();
  if (sprint) {
    return {
      sprint: sprint.sprint,
      pi: sprint.pi,
      start: sprint.start,
      end: sprint.end,
    };
  }

  if (payload.SprintStart && payload.SprintEnd) {
    return {
      sprint: sprintNo,
      pi: payload.PI || "",
      start: payload.SprintStart,
      end: payload.SprintEnd,
    };
  }

  return null;
}

function assertSubmissionFieldWindows(sprintWindow, existing, nextPayload) {
  if (!sprintWindow?.start || !sprintWindow?.end) {
    return;
  }

  const today = toDateKey(new Date());
  const start = toDateKey(sprintWindow.start);
  const end = toDateKey(sprintWindow.end);
  const goalsAchievedEnd = toDateKey(addDays(sprintWindow.end, 7));

  const objectivesEditable = today < start;
  const sprintGoalEditable = today < start;
  const goalsAchievedEditable = today >= end && today <= goalsAchievedEnd;

  const previousObjectives = normalizeObjectives(existing?.Objectives, existing?.Objective);
  const previousSprintGoal = existing?.SprintGoal ?? null;
  const previousGoalsAchieved = existing?.GoalsAchieved ?? null;

  if (!objectivesEditable && !sameObjectives(previousObjectives, nextPayload.Objectives)) {
    const err = new Error("Objectives can only be edited before the sprint start date");
    err.statusCode = 400;
    throw err;
  }

  if (!sprintGoalEditable && !sameNullableNumber(previousSprintGoal, nextPayload.SprintGoal)) {
    const err = new Error("Sprint goal can only be edited before the sprint start date");
    err.statusCode = 400;
    throw err;
  }

  if (!goalsAchievedEditable && !sameNullableNumber(previousGoalsAchieved, nextPayload.GoalsAchieved)) {
    const err = new Error("Goals achieved can only be edited from the sprint end date through one week after");
    err.statusCode = 400;
    throw err;
  }
}

async function listSubmissions(filters = {}) {
  const query = {};

  if (filters.teamKey) {
    query.ProjectKey = String(filters.teamKey).trim().toUpperCase();
  }

  if (filters.sprintNo) {
    query.SprintNo = String(filters.sprintNo).trim();
  }

  let dbQuery = Submission.find(query).sort({ updatedAt: -1 });

  const limit = Number(filters.limit);
  if (Number.isInteger(limit) && limit > 0) {
    dbQuery = dbQuery.limit(limit);
  }

  return dbQuery.lean();
}

async function getSubmission(teamKey, sprintNo) {
  return Submission.findOne({
    ProjectKey: teamKey,
    SprintNo: sprintNo
  }).lean();
}

async function upsertSubmission(payload) {
  const sprintWindow = await resolveSprintWindow(payload);
  const nextPayload = {
    ...payload,
    PI: sprintWindow?.pi != null ? String(sprintWindow.pi) : String(payload.PI || ""),
    SprintStart: sprintWindow?.start ? toDateKey(sprintWindow.start) : String(payload.SprintStart || ""),
    SprintEnd: sprintWindow?.end ? toDateKey(sprintWindow.end) : String(payload.SprintEnd || ""),
    SprintGoal: normalizeNullableNumber(payload.SprintGoal),
    GoalsAchieved: normalizeNullableNumber(payload.GoalsAchieved),
    Objectives: normalizeObjectives(payload.Objectives, payload.Objective),
    Roster: cleanRoster(payload.Roster)
  };

  const existing = await getSubmission(nextPayload.ProjectKey, nextPayload.SprintNo);
  assertSubmissionFieldWindows(sprintWindow, existing, nextPayload);

  await Submission.findOneAndUpdate(
    { ProjectKey: nextPayload.ProjectKey, SprintNo: nextPayload.SprintNo },
    nextPayload,
    {
      upsert: true,
      new: true,
      setDefaultsOnInsert: true,
      runValidators: true
    }
  );

  return { isReplace: Boolean(existing) };
}

module.exports = {
  listSubmissions,
  getSubmission,
  upsertSubmission
};

const Submission = require("../models/Submission");
const Sprint = require("../models/Sprint");
const { cleanRoster } = require("../utils/roster");

const DAY_MS = 24 * 60 * 60 * 1000;

function toDateKey(value) {
  return new Date(value).toISOString().slice(0, 10);
}

function addDays(value, days) {
  return new Date(new Date(value).getTime() + days * DAY_MS);
}

function normalizeObjectives(objectives, objective) {
  const values = Array.isArray(objectives)
    ? objectives
    : typeof objective === "string" && objective.trim()
      ? [objective]
      : [];

  return values
    .map((item) => String(item || "").trim())
    .filter(Boolean);
}

function normalizeNullableNumber(value) {
  if (value === "" || value === null || value === undefined) {
    return null;
  }

  const parsed = Number(value);
  if (!Number.isFinite(parsed)) {
    const err = new Error("Numeric submission fields must contain valid numbers");
    err.statusCode = 400;
    throw err;
  }

  return parsed;
}

function sameObjectives(left = [], right = []) {
  if (left.length !== right.length) return false;
  return left.every((value, index) => value === right[index]);
}

function sameNullableNumber(left, right) {
  return (left ?? null) === (right ?? null);
}

async function resolveSprintWindow(payload) {
  const sprintNo = String(payload.SprintNo || "").trim();
  if (!sprintNo) return null;

  const sprint = await Sprint.findOne({ sprint: sprintNo }).lean();
  if (sprint) {
    return {
      sprint: sprint.sprint,
      pi: sprint.pi,
      start: sprint.start,
      end: sprint.end,
    };
  }

  if (payload.SprintStart && payload.SprintEnd) {
    return {
      sprint: sprintNo,
      pi: payload.PI || "",
      start: payload.SprintStart,
      end: payload.SprintEnd,
    };
  }

  return null;
}

function assertSubmissionFieldWindows(sprintWindow, existing, nextPayload) {
  if (!sprintWindow?.start || !sprintWindow?.end) {
    return;
  }

  const today = toDateKey(new Date());
  const start = toDateKey(sprintWindow.start);
  const end = toDateKey(sprintWindow.end);
  const sprintStartGraceEnd = toDateKey(addDays(sprintWindow.start, 7));
  const goalsAchievedEnd = toDateKey(addDays(sprintWindow.end, 7));

  const objectivesEditable = today <= sprintStartGraceEnd;
  const sprintGoalEditable = today <= sprintStartGraceEnd;
  const goalsAchievedEditable = today >= end && today <= goalsAchievedEnd;

  const previousObjectives = normalizeObjectives(existing?.Objectives, existing?.Objective);
  const previousSprintGoal = existing?.SprintGoal ?? null;
  const previousGoalsAchieved = existing?.GoalsAchieved ?? null;

  if (!objectivesEditable && !sameObjectives(previousObjectives, nextPayload.Objectives)) {
    const err = new Error("Objectives can only be edited through one week after the sprint start date");
    err.statusCode = 400;
    throw err;
  }

  if (!sprintGoalEditable && !sameNullableNumber(previousSprintGoal, nextPayload.SprintGoal)) {
    const err = new Error("Sprint goal can only be edited through one week after the sprint start date");
    err.statusCode = 400;
    throw err;
  }

  if (!goalsAchievedEditable && !sameNullableNumber(previousGoalsAchieved, nextPayload.GoalsAchieved)) {
    const err = new Error("Goals achieved can only be edited from the sprint end date through one week after");
    err.statusCode = 400;
    throw err;
  }
}

async function listSubmissions(filters = {}) {
  const query = {};

  if (filters.teamKey) {
    query.ProjectKey = String(filters.teamKey).trim().toUpperCase();
  }

  if (filters.sprintNo) {
    query.SprintNo = String(filters.sprintNo).trim();
  }

  let dbQuery = Submission.find(query).sort({ updatedAt: -1 });

  const limit = Number(filters.limit);
  if (Number.isInteger(limit) && limit > 0) {
    dbQuery = dbQuery.limit(limit);
  }

  return dbQuery.lean();
}

async function getSubmission(teamKey, sprintNo) {
  return Submission.findOne({
    ProjectKey: teamKey,
    SprintNo: sprintNo
  }).lean();
}

async function upsertSubmission(payload) {
  const sprintWindow = await resolveSprintWindow(payload);
  const nextPayload = {
    ...payload,
    PI: sprintWindow?.pi != null ? String(sprintWindow.pi) : String(payload.PI || ""),
    SprintStart: sprintWindow?.start ? toDateKey(sprintWindow.start) : String(payload.SprintStart || ""),
    SprintEnd: sprintWindow?.end ? toDateKey(sprintWindow.end) : String(payload.SprintEnd || ""),
    SprintGoal: normalizeNullableNumber(payload.SprintGoal),
    GoalsAchieved: normalizeNullableNumber(payload.GoalsAchieved),
    Objectives: normalizeObjectives(payload.Objectives, payload.Objective),
    Roster: cleanRoster(payload.Roster)
  };

  const existing = await getSubmission(nextPayload.ProjectKey, nextPayload.SprintNo);
  assertSubmissionFieldWindows(sprintWindow, existing, nextPayload);

  await Submission.findOneAndUpdate(
    { ProjectKey: nextPayload.ProjectKey, SprintNo: nextPayload.SprintNo },
    nextPayload,
    {
      upsert: true,
      new: true,
      setDefaultsOnInsert: true,
      runValidators: true
    }
  );

  return { isReplace: Boolean(existing) };
}

module.exports = {
  listSubmissions,
  getSubmission,
  upsertSubmission
};

const test = require("node:test");
const assert = require("node:assert/strict");
const request = require("supertest");
const mongoose = require("mongoose");
const { MongoMemoryServer } = require("mongodb-memory-server");

let mongo;
let app;

async function closeConnections() {
  await mongoose.connection.dropDatabase();
  await mongoose.connection.close();
  await mongo.stop();
}

test("backend upserts and reads submissions", async (t) => {
  mongo = await MongoMemoryServer.create();
  process.env.MONGO_URI = mongo.getUri();
  process.env.VERCEL = "1";

  app = require("../server");

  t.after(async () => {
    await closeConnections();
  });

  for (const sprint of [
    { sprint: "35.1", pi: 35, start: "2099-01-01", end: "2099-01-14" },
    { sprint: "35.2", pi: 35, start: "2099-01-15", end: "2099-01-28" },
  ]) {
    const seeded = await request(app).post("/api/sprints").send(sprint);
    assert.equal(seeded.status, 201);
  }

  const payload = {
    Team: "McLaren",
    ProjectKey: "MC",
    SprintNo: "35.1",
    PI: "35",
    submittedDate: "2026-06-22",
    submittedBy: "Test User",
    TeamSize: 1,
    TotalDays: 8,
    SprintOverhead: 1.6,
    SprintCapacity: 6.4,
    DevCapacityDays: 6.4,
    TestCapacityDays: 0,
    DevPercent: 100,
    TestPercent: 0,
    SprintGoal: 6,
    GoalsAchieved: "",
    Objectives: ["Deliver checkout enhancements", "Stabilise regression suite"],
    Notes: "First submit",
    Roster: [
      { name: "Alice", role: "Full Stack Dev", ph: 0, al: 0, other: 0, pct: 100, notes: "", AvailableDays: 8 }
    ]
  };

  const first = await request(app).post("/api/submissions/upsert").send(payload);
  assert.equal(first.status, 200);
  assert.equal(first.body.success, true);
  assert.equal(first.body.isReplace, false);
  assert.ok(first.headers["x-correlation-id"]);

  const read = await request(app)
    .get("/api/submissions/MC/35.1")
    .set("x-correlation-id", "test-corr-id");
  assert.equal(read.status, 200);
  assert.equal(read.body.found, true);
  assert.equal(read.body.record.Team, "McLaren");
  assert.equal(read.body.record.SprintGoal, 6);
  assert.deepEqual(read.body.record.Objectives, ["Deliver checkout enhancements", "Stabilise regression suite"]);
  assert.equal(read.body.record.GoalsAchieved, null);
  assert.equal(read.headers["x-correlation-id"], "test-corr-id");

  const second = await request(app)
    .post("/api/submissions/upsert")
    .send({ ...payload, Notes: "Second submit", SprintGoal: 7, Objectives: ["Deliver checkout enhancements"] });
  assert.equal(second.status, 200);
  assert.equal(second.body.isReplace, true);

  const another = await request(app).post("/api/submissions/upsert").send({
    ...payload,
    Team: "Cadillac",
    ProjectKey: "CAD",
    SprintNo: "35.2",
    PI: "35",
    Notes: "Another team",
  });
  assert.equal(another.status, 200);

   const list = await request(app).get("/api/submissions");
   assert.equal(list.status, 200);
   assert.equal(Array.isArray(list.body), true);
   assert.equal(list.body.length, 2);

   const filtered = await request(app).get("/api/submissions?teamKey=MC&sprintNo=35.1");
   assert.equal(filtered.status, 200);
   assert.equal(filtered.body.length, 1);
   assert.equal(filtered.body[0].Notes, "Second submit");
    assert.equal(filtered.body[0].SprintGoal, 7);
    assert.deepEqual(filtered.body[0].Objectives, ["Deliver checkout enhancements"]);

   const limited = await request(app).get("/api/submissions?limit=1");
   assert.equal(limited.status, 200);
   assert.equal(limited.body.length, 1);
   assert.equal(limited.body[0].ProjectKey, "CAD");
});

test("backend enforces submission field edit windows", async (t) => {
  mongo = await MongoMemoryServer.create();
